import{_ as t,o,c as n,a3 as a}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"12. Redundancy And Associated Entitlements","description":"","frontmatter":{"title":"12. Redundancy And Associated Entitlements","eba":"Nurses and Midwives 2024-2028","topics":["employment","redundancy","consultation","disputes"]},"headers":[],"relativePath":"ebas/nurses-midwives/consultation-disputes/12-redundancy-and-associated-entitlements.md","filePath":"ebas/nurses-midwives/consultation-disputes/12-redundancy-and-associated-entitlements.md"}'),r={name:"ebas/nurses-midwives/consultation-disputes/12-redundancy-and-associated-entitlements.md"};function s(i,e,p,l,d,c){return o(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="_12-redundancy-and-associated-entitlements" tabindex="-1">12. Redundancy And Associated Entitlements <a class="header-anchor" href="#_12-redundancy-and-associated-entitlements" aria-label="Permalink to &quot;12. Redundancy And Associated Entitlements&quot;">​</a></h1><p><strong>12.1</strong> Arrangement</p><p>This clause is arranged as follows:</p><p><strong>(a)</strong> Arrangement (clause 12.1);</p><p><strong>(b)</strong> Definitions (clause 12.2);</p><p><strong>(c)</strong> Redeployment (clause 12.3);</p><p><strong>(d)</strong> Support to Affected Employees (clause 12.4);</p><p><strong>(e)</strong> Salary maintenance (clause 12.5);</p><p><strong>(f)</strong> Relocation (clause 12.6);</p><p><strong>(g)</strong> Employment terminates due to redundancy (clause 12.7); and</p><p><strong>(h)</strong> Exception to application of Victorian Government&#39;s policy with respect to severance pay (clause 12.8).</p><p><strong>12.2</strong> Definitions</p><p><strong>(a)</strong> Affected Employee for this clause 12 means an Employee whose role will be redundant.</p><p><strong>(b)</strong> Comparable Role means an ongoing role that:</p><p><strong>(i)</strong> is the same occupation as that of the Affected Employee&#39;s redundant position or if not, is in an occupation acceptable to the Affected Employee; and</p><p><strong>(ii)</strong> is any of the following:</p><p><strong>(A)</strong> in the same clinical specialty as that of the Affected Employee&#39;s former position;</p><p><strong>(B)</strong> in a clinical specialty acceptable to the Affected Employee; or</p><p><strong>(C)</strong> a position that with the reasonable support described at 12.3(g), the Affected Employee could undertake; and</p><p><strong>(iii)</strong> is the same Level as the Affected Employee&#39;s redundant position;</p><p><strong>(iv)</strong> takes into account the number of ordinary hours normally worked by the Affected Employee;</p><p><strong>(v)</strong> is a Reasonable Distance from the Affected Employee&#39;s current work location;</p><p><strong>(vi)</strong> takes the Affected Employee&#39;s personal circumstances, including family responsibilities, into account; and</p><p><strong>(vii)</strong> takes account of health and safety considerations.</p><p><strong>(c)</strong> Consultation is as defined at <a href="/eba/ebas/nurses-midwives/consultation-disputes/11-consultation.html">clause 11</a> (Consultation) of this Agreement.</p><p><strong>(d)</strong> Continuity of Service at 12.8 means that the service of the Employee is treated as unbroken and that the cap on the transfer of personal leave at <a href="/eba/ebas/nurses-midwives/leave/61-personal-leave.html">clause 61.8</a> does not apply. However, continuity of service is broken where an Employer pays out accrued annual leave or long service leave upon termination in accordance with this Agreement.</p><p><strong>(e)</strong> Level for the purposes of this clause 12 means a weekly salary in Schedule 2 that is at least equal to or higher than the weekly salary in Schedule 2 for the Role the Employee held immediately prior to redundancy.</p><p><strong>(f)</strong> Reasonable Distance means a distance that has regard to the Employee&#39;s original work location, current home address, capacity of the Employee to travel,</p><p>additional travelling time, effects on the personal circumstances of the affected Employee, including family commitments and responsibilities and other matters raised by the Employee, or assistance provided by their Employer.</p><p><strong>(g)</strong> Redeployment period means a period of 13 weeks from the time the Employer notifies the Affected Employee in writing that consultation under <a href="/eba/ebas/nurses-midwives/consultation-disputes/11-consultation.html">clause 11</a> is complete and that the redeployment period has begun.</p><p><strong>(h)</strong> Redundancy means the Employer no longer requires the Affected Employee&#39;s job to be performed by anyone because of changes in the operational requirements of the Employer&#39;s enterprise.</p><p><strong>(i)</strong> Relocation means an Affected Employee is required to move to a different Campus as a result of an organisational change on either a temporary or permanent basis.</p><p><strong>(j)</strong> Salary maintenance means an amount representing the difference between what the Affected Employee was normally paid immediately prior to the Affected Employee&#39;s role being made redundant and the amount paid in the Affected Employee&#39;s new role following redeployment.</p><p><strong>12.3</strong> Redeployment</p><p><strong>(a)</strong> An Affected Employee whose role will be redundant will be considered for redeployment during the Redeployment period.</p><p><strong>(b)</strong> Employee to be advised in writing</p><p>The Affected Employee must be advised in writing of:</p><p><strong>(i)</strong> the date the Affected Employee&#39;s role is to be redundant;</p><p><strong>(ii)</strong> details of the redeployment process;</p><p><strong>(iii)</strong> the reasonable support that will be provided in accordance with subclause 12.3(g); and</p><p><strong>(iv)</strong> the Affected Employee&#39;s rights and obligations.</p><p><strong>(c)</strong> Employer obligations</p><p>The Employer will:</p><p><strong>(i)</strong> make every effort to redeploy the Affected Employee to a Comparable Role in terms of classification, grade and income, including appointing a case manager to provide the Affected Employee with support and assistance;</p><p><strong>(ii)</strong> take into account the personal circumstances of the Affected Employee, including family commitments and responsibilities; and</p><p><strong>(iii)</strong> where the Employer is creating a new role/s substantially similar to the Affected Employee&#39;s redundant role; give priority to the redeployment of an Affected Employee/s to the new position/s before considering applicants that are not Affected Employees.</p><p>Example: The Employer needs fewer Employees to do particular work and roles are being restructured to take this into account. In a</p><p>&#39;spill and fill&#39;, the Employer will consider the Affected Employees for the new roles before other applicants.</p><p><strong>(d)</strong> Employee obligations</p><p>The Employee must actively participate in the redeployment process including:</p><p><strong>(i)</strong> identifying appropriate retraining needs;</p><p><strong>(ii)</strong> developing a resume/CV to assist in securing redeployment; and/or</p><p><strong>(iii)</strong> actively monitoring and exploring appropriate redeployment opportunities and working with the appointed case manager.</p><p><strong>(e)</strong> Rejecting a Comparable Role</p><p>Where an Affected Employee rejects an offer of redeployment to a Comparable Role (as defined), the Affected Employee may be ineligible for a departure package referred to at clause 12.7.</p><p><strong>(f)</strong> Temporary alternative duties</p><p>An Affected Employee awaiting redeployment may be transferred to temporary alternative duties within the same Campus, or where part of the Employee&#39;s existing employment conditions (or by agreement) at another Campus. Such temporary duties will be in accordance with the Affected Employee&#39;s skills, experience, clinical area and profession.</p><p><strong>(g)</strong> Support for redeployment</p><p>For an available role to be considered a Comparable Role, the Employer must provide the reasonable support necessary for the Affected Employee to perform the role which may include:</p><p><strong>(i)</strong> theory training relevant to the clinical area or environment of the role into which the Affected Employee is to be redeployed;</p><p><strong>(ii)</strong> a defined period of up to 12 weeks in which the Affected Employee works in a supernumerary capacity;</p><p><strong>(iii)</strong> support from educational staff in the clinical environment; and/or</p><p><strong>(iv)</strong> a review at 12 weeks or earlier to determine what, if any, further training is required.</p><p><strong>(h)</strong> Where no redeployment available</p><p>If at any time during the Redeployment period it is agreed that it is unlikely that the Affected Employee will be successfully redeployed, the Affected Employee may accept a redundancy package. Where this occurs, the Affected Employee will be entitled to an additional payment of the lesser of 13 weeks or the remaining Redeployment period.</p><p><strong>(i)</strong> Non-Comparable Role</p><p>An Affected Employee may agree to be redeployed to a role that is not a Comparable Role.</p><p><strong>12.4</strong> Support to Affected Employees</p><p>The Employer will provide Affected Employees whose position has been declared redundant with support and assistance which will include, where relevant:</p><p><strong>(a)</strong> counselling and support services;</p><p><strong>(b)</strong> retraining;</p><p><strong>(c)</strong> preparation of job applications;</p><p><strong>(d)</strong> interview coaching;</p><p><strong>(e)</strong> time off to attend job interviews; and</p><p><strong>(f)</strong> funding of independent financial advice for Employees eligible to receive a separation package.</p><p>Other assistance may include but is not limited to career planning.</p><p><strong>12.5</strong> Salary Maintenance</p><p><strong>(a)</strong> Entitlement to salary maintenance</p><p>An Affected Employee who is successfully redeployed will be entitled to salary maintenance where the Affected Employee&#39;s pay is reduced because the new role:</p><p><strong>(i)</strong> is a lower Level, grade, subgrade or increment;</p><p><strong>(ii)</strong> involves working fewer hours; and/or</p><p><strong>(iii)</strong> removes eligibility for penalties, loadings and the like.</p><p><strong>(b)</strong> Period of salary maintenance</p><p>Salary maintenance will be for a period of 52 weeks from the date the Affected Employee is redeployed except where the Affected Employee:</p><p><strong>(i)</strong> accepts another position within the salary maintenance period; and</p><p><strong>(ii)</strong> is paid in the other position an amount equal to or greater than the role that was made redundant.</p><p><strong>(c)</strong> Preservation of accrued leave</p><p>An Affected Employee entitled to salary maintenance will have their:</p><p><strong>(i)</strong> long service leave and annual leave accruals preserved before redeployment. Specifically, the value of the leave immediately prior to redeployment will not be reduced as a result of redeployment; and</p><p><strong>(ii)</strong> personal leave preserved in hours.</p><p><strong>12.6</strong> Relocation</p><p><strong>(a)</strong> Employer to advise in writing of relocation</p><p>As soon as practicable but no less than seven (7) days after a decision is made by the Employer to temporarily or permanently relocate an Affected Employee,</p><p>the Employer will advise the Affected Employee in writing of the decision, the proposed timing of the relocation and any other alternatives available to the Affected Employee. In addition, the Employer will:</p><p><strong>(i)</strong> ensure the relocation is a Reasonable Distance, unless otherwise agreed;</p><p><strong>(ii)</strong> ensure that the Affected Employee is provided with information on the new location&#39;s amenities, layout and local operations prior to the relocation; and</p><p><strong>(iii)</strong> consult with the Union regarding the content of such information.</p><p><strong>(b)</strong> Entitlement to relocation allowance</p><p>An Affected Employee is entitled to relocation allowance where permanent or temporary relocation results in additional cost to the Affected Employee for travel and/or other expenses.</p><p><strong>(c)</strong> Employee to provide written estimate</p><p>The Affected Employee must make a written application to the Employer with a written estimate of the additional travelling cost and other expenses for the period of redeployment up to a maximum of 12 months.</p><p><strong>(d)</strong> Payment</p><p><strong>(i)</strong> The Employer will pay the Affected Employee a relocation allowance up to $1,900.00 based on the written estimate of the Affected Employee referred to at (c) where the Employer accepts that estimate represents the additional cost to the Affected Employee. The allowance shall be paid as a lump sum.</p><p><strong>(ii)</strong> When considering the Affected Employee&#39;s estimate, the Employer may have regard to the Reasonable Distance.</p><p><strong>(iii)</strong> In the event of a dispute about the Affected Employee&#39;s estimate it will be resolved under <a href="/eba/ebas/nurses-midwives/consultation-disputes/13-dispute-resolution-procedure.html">clause 13</a> (Dispute Resolution Procedure).</p><p><strong>(e)</strong> Exceptions</p><p><strong>(i)</strong> An Affected Employee is not entitled to the relocation allowance if the site or Campus to which the Affected Employee is being relocated is a location to which they can be expected to be deployed as part of their existing employment conditions.</p><p><strong>(f)</strong> Fixed term Employees not excluded</p><p>An Affected Employee on a fixed term contract who is relocated will be covered by the terms of this clause for the duration of the fixed term contract.</p><p><strong>12.7</strong> Employment terminates due to redundancy</p><p>The Victorian Government&#39;s policy with respect to public sector redundancy and the entitlements upon termination of employment as a result of redundancy are set out in the Public Sector Industrial Relations Policies 2015. The policy as at the time this Agreement comes into operation applies to Employees but does not form part of this Agreement.</p><p><strong>12.8</strong> Exception to application of Victorian Government&#39;s policy with respect to severance pay</p><p><strong>(a)</strong> Where the Affected Employee&#39;s Employer secures a Comparable Role (as defined) with another Employer covered by this Agreement, which:</p><p><strong>(i)</strong> is within a Reasonable Distance of the work site of the redundant position; and</p><p><strong>(ii)</strong> provides Continuity of Service; and</p><p><strong>(iii)</strong> where the Comparable Role results in a loss of income, salary maintenance at clause 12.5 will apply; and</p><p><strong>(iv)</strong> where relevant, consistent with the financial and other support provided to an internal redeployee,</p><p>the Employee will be considered successfully redeployed as though the employment was with the same Employer and no severance pay will apply.</p><p>Plain language terms: redundancy pay, retrenchment, position made redundant.</p>',119)])])}const g=t(r,[["render",s]]);export{h as __pageData,g as default};
